  1→import { doorOutlineOnWall, positionOnWall, projectPointOnWall, wallAngle, wallLength, wallOutline, windowOutlineOnWall } from '@/geometry/wallGeometry';
  2→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
  3→
  4→const EPSILON = 1e-6;
  5→
  6→function clamp(value, min, max) {
  7→  return Math.max(min, Math.min(max, value));
  8→}
  9→
 10→function buildOpeningDescriptor(kind, source, context) {
 11→  const outlineInfo = kind === 'door'
 12→    ? doorOutlineOnWall(context.sourceWall, source)
 13→    : windowOutlineOnWall(context.sourceWall, source);
 14→
 15→  const sourceCenterAlong = projectPointOnWall(context.sourceWall, outlineInfo.center);
 16→  const sourceStartAlong = sourceCenterAlong - source.width / 2;
 17→  const sourceEndAlong = sourceCenterAlong + source.width / 2;
 18→  const clippedSourceStartAlong = clamp(sourceStartAlong, context.trimStartAlong, context.trimEndAlong);
 19→  const clippedSourceEndAlong = clamp(sourceEndAlong, context.trimStartAlong, context.trimEndAlong);
 20→  const visibleWidth = clippedSourceEndAlong - clippedSourceStartAlong;
 21→
 22→  const baseElevation = context.wallBase + (source.sillHeight ?? 0);
 23→  const topElevation = baseElevation + (source.height ?? 0);
 24→  const visibleBaseElevation = clamp(baseElevation, context.wallBase, context.wallTop);
 25→  const visibleTopElevation = clamp(topElevation, context.wallBase, context.wallTop);
 26→  const visibleHeight = visibleTopElevation - visibleBaseElevation;
 27→
 28→  if (visibleWidth <= EPSILON || visibleHeight <= EPSILON) {
 29→    return null;
 30→  }
 31→
 32→  const startAlong = clippedSourceStartAlong - context.trimStartAlong;
 33→  const endAlong = clippedSourceEndAlong - context.trimStartAlong;
 34→  const centerAlong = (startAlong + endAlong) / 2;
 35→  const startPoint = positionOnWall(context.renderWall, startAlong);
 36→  const endPoint = positionOnWall(context.renderWall, endAlong);
 37→  const centerPoint = positionOnWall(context.renderWall, centerAlong);
 38→
 39→  return {
 40→    id: source.id,
 41→    kind,
 42→    wallId: context.wall.id,
 43→    sourceId: source.id,
 44→    angle: wallAngle(context.renderWall),
 45→    wallThickness: context.renderWall.thickness,
 46→    width: source.width,
 47→    height: source.height ?? 0,
 48→    sillHeight: source.sillHeight ?? 0,
 49→    startAlong,
 50→    endAlong,
 51→    centerAlong,
 52→    visibleWidth,
 53→    visibleBaseElevation,
 54→    visibleTopElevation,
 55→    visibleHeight,
 56→    startPoint,
 57→    endPoint,
 58→    centerPoint,
 59→    outline: wallOutline({
 60→      start: startPoint,
 61→      end: endPoint,
 62→      thickness: context.renderWall.thickness,
 63→    }),
 64→    metadata: {
 65→      wallId: context.wall.id,
 66→      floorId: context.floorId,
 67→      sourceStartAlong,
 68→      sourceEndAlong,
 69→      clippedSourceStartAlong,
 70→      clippedSourceEndAlong,
 71→    },
 72→  };
 73→}
 74→
 75→export function buildWallPreviewContext(floor, wall, floorLevel) {
 76→  const wallRenderData = getWallRenderData(wall, floor.columns || []);
 77→  const sourceWall = wallRenderData.wall;
 78→  const renderWall = wallRenderData.renderWall;
 79→  const trimStartAlong = projectPointOnWall(sourceWall, renderWall.start);
 80→  const trimEndAlong = projectPointOnWall(sourceWall, renderWall.end);
 81→  const context = {
 82→    floorId: floor.id,
 83→    wall,
 84→    sourceWall,
 85→    renderWall,
 86→    wallRenderData,
 87→    trimStartAlong,
 88→    trimEndAlong,
 89→    renderLength: wallLength(renderWall),
 90→    wallBase: floorLevel,
 91→    wallTop: floorLevel + (wall.height ?? 0),
 92→  };
 93→
 94→  const openings = [
 95→    ...(floor.doors || []).filter((item) => item.wallId === wall.id).map((door) => (
 96→      buildOpeningDescriptor('door', door, context)
 97→    )),
 98→    ...(floor.windows || []).filter((item) => item.wallId === wall.id).map((windowItem) => (
 99→      buildOpeningDescriptor('window', windowItem, context)
100→    )),
101→  ]
102→    .filter(Boolean)
103→    .sort((left, right) => left.startAlong - right.startAlong);
104→
105→  return {
106→    ...context,
107→    openings,
108→  };
109→}
110→
111→export function buildWallPreviewContexts(floor, floorLevel) {
112→  return (floor.walls || []).map((wall) => buildWallPreviewContext(floor, wall, floorLevel));
113→}
114→
115→export function buildWallSolidSegments(context) {
116→  if (context.renderLength <= EPSILON || context.wallTop - context.wallBase <= EPSILON) {
117→    return [];
118→  }
119→
120→  const segments = [];
121→  let cursor = 0;
122→  let segmentIndex = 0;
123→
124→  const pushSegment = (startAlong, endAlong, baseElevation, topElevation) => {
125→    if (endAlong - startAlong <= EPSILON) return;
126→    if (topElevation - baseElevation <= EPSILON) return;
127→
128→    segmentIndex += 1;
129→    segments.push({
130→      id: `${context.wall.id}-segment-${segmentIndex}`,
131→      wallId: context.wall.id,
132→      floorId: context.floorId,
133→      startPoint: positionOnWall(context.renderWall, startAlong),
134→      endPoint: positionOnWall(context.renderWall, endAlong),
135→      thickness: context.renderWall.thickness,
136→      baseElevation,
137→      topElevation,
138→    });
139→  };
140→
141→  for (const opening of context.openings) {
142→    const openingStart = Math.max(cursor, opening.startAlong);
143→    const openingEnd = Math.max(openingStart, opening.endAlong);
144→
145→    pushSegment(cursor, openingStart, context.wallBase, context.wallTop);
146→
147→    if (opening.visibleBaseElevation > context.wallBase + EPSILON) {
148→      pushSegment(
149→        openingStart,
150→        openingEnd,
151→        context.wallBase,
152→        Math.min(opening.visibleBaseElevation, context.wallTop)
153→      );
154→    }
155→
156→    if (opening.visibleTopElevation < context.wallTop - EPSILON) {
157→      pushSegment(
158→        openingStart,
159→        openingEnd,
160→        Math.max(opening.visibleTopElevation, context.wallBase),
161→        context.wallTop
162→      );
163→    }
164→
165→    cursor = Math.max(cursor, openingEnd);
166→  }
167→
168→  pushSegment(cursor, context.renderLength, context.wallBase, context.wallTop);
169→  return segments;
170→}
