 3→function mergeBounds(current, next) {
 4→  if (!next) return current;
 5→  if (!current) return { ...next };
 6→
 7→  return {
 8→    minX: Math.min(current.minX, next.minX),
 9→    maxX: Math.max(current.maxX, next.maxX),
10→    minY: Math.min(current.minY, next.minY),
11→    maxY: Math.max(current.maxY, next.maxY),
12→    minElevation: Math.min(current.minElevation, next.minElevation),
13→    maxElevation: Math.max(current.maxElevation, next.maxElevation),
14→  };
15→}
16→
17→function boundsFromObjects(objects = []) {
18→  return objects.reduce((accumulator, objectDescriptor) => (
19→    mergeBounds(accumulator, objectDescriptor.bounds)
20→  ), null);
21→}
22→
23→function createFallbackBounds(activeFloor) {
24→  const level = activeFloor?.level ?? 0;
25→  return {
26→    minX: -1500,
27→    maxX: 1500,
28→    minY: -1500,
29→    maxY: 1500,
30→    minElevation: level,
31→    maxElevation: level + 3000,
32→  };
33→}
34→
35→export function buildPreviewScene(project, options = {}) {
36→  const floors = project?.floors || [];
37→  const activeFloorId = options.activeFloorId ?? floors[0]?.id ?? null;
38→  const activeFloor = floors.find((floor) => floor.id === activeFloorId) || null;
39→  const visibleFloorIds = new Set(options.visibleFloorIds || (activeFloorId ? [activeFloorId] : []));
40→
41→  const floorDescriptors = floors.map((floor) => {
42→    const objects = buildFloorPreviewObjects(floor);
43→    return {
44→      floorId: floor.id,
45→      name: floor.name,
46→      level: floor.level ?? 0,
47→      visible: visibleFloorIds.has(floor.id),
48→      objects,
49→      bounds: boundsFromObjects(objects),
50→    };
51→  });
52→
53→  const visibleObjects = floorDescriptors
54→    .filter((floor) => floor.visible)
55→    .flatMap((floor) => floor.objects);
56→  const bounds = boundsFromObjects(visibleObjects) || createFallbackBounds(activeFloor);
57→
58→  return {
59→    activeFloorId,
60→    visibleFloorIds: [...visibleFloorIds],
61→    floors: floorDescriptors,
62→    bounds,
63→    defaultTarget: {
64→      x: (bounds.minX + bounds.maxX) / 2,
65→      y: (bounds.minElevation + bounds.maxElevation) / 2,
66→      z: (bounds.minY + bounds.maxY) / 2,
67→    },
68→    groundLevel: activeFloor?.level ?? 0,
69→    hasVisibleObjects: visibleObjects.length > 0,
70→  };
71→}
