 41→export function nextSectionLabel(existingCuts = []) {
 42→  const usedLetters = new Set(
 43→    existingCuts
 44→      .map(c => {
 45→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 46→        return match ? match[1] : null;
 47→      })
 48→      .filter(Boolean)
 49→  );
 50→  for (let i = 0; i < 26; i++) {
 51→    const letter = String.fromCharCode(65 + i);
 52→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 53→  }
 54→  return `Section ${existingCuts.length + 1}`;
 55→}
