143→export default function WindowRenderer({ windows, walls }) {
144→  return (
145→    <g className="windows">
146→      {windows.map(win => {
147→        const wall = walls.find(w => w.id === win.wallId);
148→        if (!wall) return null;
149→
150→        const info = windowOutlineOnWall(wall, win);
151→        const type = win.type || 'standard';
152→
153→        return (
154→          <g key={win.id} data-id={win.id} data-type="window">
155→            {/* White rectangle to mask wall */}
156→            <polygon
157→              points={`${info.p1.x},${info.p1.y} ${info.p2.x},${info.p2.y} ${info.p3.x},${info.p3.y} ${info.p4.x},${info.p4.y}`}
158→              fill="white"
159→              stroke="none"
160→            />
161→            {type === 'standard' && <StandardWindow info={info} wall={wall} />}
162→            {type === 'casement' && <CasementWindow win={win} info={info} />}
163→            {type === 'awning' && <AwningWindow win={win} info={info} />}
164→            {type === 'fixed' && <FixedWindow info={info} />}
165→          </g>
166→        );
167→      })}
168→    </g>
169→  );
170→}
