 43→function buildSlabRects(floor, view) {
 44→  return (floor.slabs || []).flatMap((slab) => {
 45→    const slabTop = getSlabTopLevel(slab);
 46→    const slabBottom = getSlabBottomLevel(slab);
 47→
 48→    return buildSlabElevationBands(slab, view)
 49→      .map((band) => createSceneRect(
 50→        `slab-elev-${slab.id}-${band.edgeIndex}`,
 51→        'slab',
 52→        band,
 53→        slabBottom,
 54→        slabTop,
 55→        { sourceId: slab.id }
 56→      ))
 57→      .filter(Boolean);
 58→  });
 59→}
